    private WorkerHandle cursor;

    WorkerHandle cursorFor(TimelineLedger ledger) {
        TimelineFrame frame = ledger.current();
        if (cursor != null && !cursor.matches(frame)) {
            cursor.close();
            cursor = null;
        }

        if (cursor == null) {
            cursor = new WorkerHandle(frame);
        }

        return cursor;
    }

    @Override
    public void close() {
        if (cursor != null) {
            cursor.close();
            cursor = null;
        }
    }
}
